import Logo from '../../logo.png';
import './header.css';

const Header = () => {
    return(        
        <header className="row">            
            <div className='col-11'>
                <h1>NPTFC Tigers U9 23-24</h1>
            </div>
            <div className='col-1'>
                <img src={Logo} className="App-logo" alt="logo"></img>
            </div>
        </header>        
    );
}
export default Header;
